def extract_paragraphs(result: AnalyzeResult) -> list:
    """
    Extract all paragraphs from the document, including bounding regions and offsets.

    Args:
        result (AnalyzeResult): The result object from the document analysis.

    Returns:
        list: A list of dictionaries containing content, role, bounding region, page number, and span info.
    """
    try:
        paragraphs = []
        if result.paragraphs:
            # Sort by offset (best practice)
            result.paragraphs.sort(
                key=lambda p: (p.spans[0].offset if p.spans else 0)
            )

            for paragraph in result.paragraphs:
                para_info = {
                    "content": paragraph.content,
                    "offset": paragraph.spans[0].offset if paragraph.spans else None,
                    "length": paragraph.spans[0].length if paragraph.spans else None,
                    "pages": [],
                    "bounding_regions": []
                }

                if paragraph.bounding_regions:
                    for region in paragraph.bounding_regions:
                        page = region.page_number
                        polygon_raw = region.polygon  # list of floats [x1, y1, x2, y2, ...]
                        polygon = [(polygon_raw[i], polygon_raw[i + 1]) for i in range(0, len(polygon_raw), 2)] if polygon_raw else None

                        para_info["pages"].append(page)
                        para_info["bounding_regions"].append({
                            "page": page,
                            "polygon": polygon
                        })
                else:
                    para_info["pages"].append(None)
                    para_info["bounding_regions"].append(None)

                paragraphs.append(para_info)

        logger.info(f"extract_paragraphs: Extracted {len(paragraphs)} structured paragraphs")
        return paragraphs

    except Exception as e:
        logger.error(f"extract_paragraphs - Failed to extract all paragraphs from the document: {str(e)}")
        raise

def extract_key_value_pairs(result: AnalyzeResult) -> dict:
    """
    Extract key-value pairs as a dictionary.

    Args:
        result (AnalyzeResult): The result object from the document analysis.

    Returns:
        dict: A dictionary with keys and values.
    """
    try:
        kv_dict = {}
        if hasattr(result, "key_value_pairs") and result.key_value_pairs:
            for kv in result.key_value_pairs:
                key = kv.key.content if kv.key else "Unknown Key"
                value = kv.value.content if kv.value else "Unknown Value"
                kv_dict[key] = value
        logger.info(f"extract_key_value_pairs: Extracted {len(kv_dict)} key-value pairs")

        return kv_dict

    except Exception as e:
        logger.error(f"extract_key_value_pairs - Failed to extract all key-value pairs from the document: {str(e)}")
        raise

def search_paragraphs(paragraphs: list, keywords: list) -> dict:
    """
    Search paragraphs for specific keywords (case-sensitive) and return all matches,
    including page number and bounding regions.

    Args:
        paragraphs (list): List of paragraph objects, each containing 'content', 'bounding_regions', and 'page_number'.
        keywords (list): List of keywords to search for.

    Returns:
        dict: A dictionary mapping keywords to all matching paragraph's content, page number, and bounding regions.
    """
    try:
        # Initialize empty lists for each keyword
        matches = {keyword: [] for keyword in keywords}  

        for keyword in keywords:
            for paragraph in paragraphs:
                if keyword in paragraph["content"]:  # Case-sensitive match
                    # Extract relevant details: content, page number, bounding regions
                    paragraph_info = {
                        "content": paragraph["content"],
                        "page_number": paragraph["pages"][0] if paragraph["pages"] else "N/A",
                        "bounding_regions": [
                            {
                                "page": region["page"],
                                "polygon": region["polygon"]
                            }
                            for region in paragraph["bounding_regions"]
                        ] if paragraph["bounding_regions"] else []
                    }

                    # Add to the list of matches for this keyword
                    matches[keyword].append(paragraph_info)  

            # If no match is found, store empty data
            if not matches[keyword]:
                matches[keyword] = [{"content": "", "page_number": "N/A", "bounding_regions": []}]

        return matches

    except Exception as e:
        logger.error(f"search_paragraphs - Failed to search paragraphs for specific keywords: {keywords}: {str(e)}")
        raise
